# Subtask: 实现 push 方法  [✓ passed]
# ════════════════════════════════════════════════════════════
from typing import Any

class Stack:
    def __init__(self):
        # 初始化一个空列表来存储栈中的元素
        self.items = []

    def push(self, item: Any) -> None:
        """
        将元素 item 添加到栈顶。

        参数:
        item (Any): 要添加到栈顶的元素。
        """
        # 使用列表的 append 方法将元素添加到列表末尾，即栈顶
        self.items.append(item)


