# Subtask: 实现 pop 方法  [✓ passed]
# ════════════════════════════════════════════════════════════
from typing import Any

class Stack:
    def __init__(self):
        # 初始化一个空列表来存储栈元素
        self.items = []

    def pop(self) -> Any:
        """
        移除并返回栈顶元素。

        如果栈为空，抛出 IndexError 异常。

        Returns:
            Any: 栈顶元素。
        """
        # 检查栈是否为空
        if len(self.items) == 0:
            # 若为空，抛出 IndexError 异常
            raise IndexError("栈为空")
        # 若不为空，使用列表的 pop 方法移除并返回栈顶元素
        return self.items.pop()


