# Subtask: 实现 peek 方法  [✓ passed]
# ════════════════════════════════════════════════════════════
from typing import Any

class Stack:
    def __init__(self):
        # 初始化一个空列表来存储栈中的元素
        self.items = []

    def peek(self) -> Any:
        """
        返回栈顶元素，但不移除它。

        如果栈为空，抛出 IndexError 异常。

        Returns:
            Any: 栈顶元素。
        """
        # 检查栈是否为空
        if len(self.items) == 0:
            # 若栈为空，抛出 IndexError 异常
            raise IndexError("peek from empty stack")
        # 若栈不为空，返回栈顶元素
        return self.items[-1]


