# Subtask: 实现 is_empty 方法  [✓ passed]
# ════════════════════════════════════════════════════════════
class Stack:
    def __init__(self):
        # 初始化一个空列表作为栈的底层存储结构
        self.items = []

    def is_empty(self) -> bool:
        """
        判断栈是否为空。

        返回值:
            bool: 如果栈为空返回 True，否则返回 False。
        """
        # 通过检查列表长度是否为 0 来判断栈是否为空
        return len(self.items) == 0